// Turn the user's form answers into a LinkedIn-scraper search input.
const f = $('Job preferences').first().json;

const keywords = String(f['Target role or keywords'] || '')
  .split(',').map(s => s.trim()).filter(Boolean).slice(0, 3);

const location = (String(f['Preferred locations'] || '').split(',')[0] || '').trim() || 'India';

const senMap = {
  'fresher / entry': 'entry-level', 'fresher': 'entry-level', 'entry': 'entry-level',
  'associate': 'associate', 'mid': 'mid-senior', 'senior': 'mid-senior'
};
const exp = senMap[String(f['Seniority'] || '').toLowerCase()];

const input = {
  keyword: keywords.length ? keywords : ['AI Engineer'],
  location: location,
  publishedAt: 'r604800',        // last 7 days (fresh jobs)
  saveOnlyUniqueItems: true,     // don't pay for duplicates
  enrichCompanyData: false,      // faster + cheaper
  maxItems: 150                  // actor enforces a 150 minimum
};
if (exp) input.experienceLevel = [exp];

return [{ json: input }];

// CHEAP PRE-FILTER + DEDUP  (runs before the AI, so the AI only sees real candidates)
// Uses the user's form answers. Free + instant. Cuts hundreds of rows to a handful.
const f = $('Job preferences').first().json;
const seniority = String(f['Seniority'] || '').toLowerCase();
const isJunior = /fresher|entry|associate/.test(seniority);
const wantLocs = String(f['Preferred locations'] || '')
  .toLowerCase().split(/[,;/]| or /).map(s => s.trim()).filter(Boolean);

const seniorTitle = /(senior|sr\.?|lead|principal|staff|architect|manager|director|head|vp|avp|\biii\b|sde-?3|sde-?ii)/i;

const seen = new Set();
const out = [];
for (const it of $input.all()) {
  const r = it.json;
  const title = String(r.jobTitle || '');
  const loc = String(r.location || '').toLowerCase();

  // 1) DEDUP within this batch (same job posted many times)
  const key = (String(r.applyUrl || r.jobUrl || '') || (String(r.companyName || '') + '|' + title))
    .toLowerCase().trim();
  if (!key || seen.has(key)) continue;
  seen.add(key);

  // 2) Drop roles that are clearly too senior for a junior seeker
  if (isJunior && seniorTitle.test(title)) continue;
  if (/executive/i.test(String(r.experienceLevel || ''))) continue;

  // 3) Drop roles demanding too many years (structured field first, then the JD text)
  let maxY = -1;
  for (let i = 0; i < 5; i++) {
    const m = String(r['yearsOfExperience/' + i + '/years'] || '').match(/(\d+)/);
    if (m) maxY = Math.max(maxY, parseInt(m[1]));
  }
  // also scan the description text, e.g. "5+ years", "5-10 years", "minimum 4 years"
  const desc = String(r.jobDescription || '');
  const re = /(\d+)\s*(?:\+|-\s*\d+)?\s*(?:years|yrs)/gi;
  let tm;
  while ((tm = re.exec(desc)) !== null) {
    const n = parseInt(tm[1]);
    if (n <= 20) maxY = Math.max(maxY, n);
  }
  if (isJunior && maxY >= 4) continue;
  if (maxY >= 8) continue;

  // 4) Location: if the user named locations, keep only matches (or remote)
  if (wantLocs.length) {
    const ok = wantLocs.some(w => w && loc.includes(w)) || /remote|anywhere/.test(loc);
    if (!ok) continue;
  }

  out.push({ json: r });
}
return out;

// Build ONE screening prompt: relevance + eligibility in a single AI call.
const f = $('Job preferences').first().json;
const j = $json;
const jd = String(j.jobDescription || '').slice(0, 4500);

$json.matchPrompt =
'You are a strict job screener for a job seeker. They want -> role/keywords: ' + (f['Target role or keywords'] || '') +
'. seniority: ' + (f['Seniority'] || '') +
'. preferred locations: ' + (f['Preferred locations'] || '') +
'. their top skills: ' + (f['Your top skills'] || '') +
'. deal-breakers (reject if the job requires any of these): ' + (f['Deal-breakers (skip jobs needing these)'] || '') +
'. Infer the candidate experience from their seniority (Fresher/Entry = 0 to 1 years). Judge THIS job on BOTH: ' +
'(1) relevance to what they want, and (2) eligibility - read the description for required years like "3+ years" or "5-10 years" and for senior/lead/principal titles. ' +
'Return ONLY JSON: {"relevant": true or false, "fit": 0 to 100, "verdict": "APPLY or STRETCH or REJECT", "reason": "one short sentence naming years required vs candidate"}. ' +
'Rules: REJECT if the job needs clearly more years than the candidate has, is senior/lead/principal/manager level, requires a deal-breaker, or is a different field. APPLY if a genuine fit. STRETCH if close. ' +
'JOB TITLE: ' + (j.jobTitle || '') + '. COMPANY: ' + (j.companyName || '') + '. LOCATION: ' + (j.location || '') + '. LEVEL: ' + (j.experienceLevel || '') + '. DESCRIPTION: ' + jd;

return $json;

// Parse the combined screen output, gate out REJECTs, keep the best 5.
const prompts = $('Build Match Prompt').all();
const inputs = $input.all();
const scored = [];
for (let i = 0; i < inputs.length; i++) {
  let m = { relevant: false, fit: 0, verdict: 'REJECT', reason: '' };
  try {
    let t = inputs[i].json.output;
    if (typeof t !== 'string') t = JSON.stringify(t || {});
    t = t.replace(/\x60\x60\x60json|\x60\x60\x60/g, '').trim();
    m = JSON.parse(t);
  } catch (e) {}
  const lead = (prompts[i] && prompts[i].json) || inputs[i].json;
  scored.push({ json: {
    ...lead,
    _fit: Number(m.fit) || 0,
    verdict: String(m.verdict || 'REJECT').toUpperCase(),
    reason: m.reason || '',
    _relevant: !!m.relevant
  }});
}
// Keep anything not REJECTed with a decent score. If none, fall back to the best few.
let keep = scored.filter(r => r.json.verdict !== 'REJECT' && r.json._fit >= 40);
if (keep.length === 0) keep = scored.filter(r => r.json._fit >= 30);
keep.sort((a, b) => b.json._fit - a.json._fit);
return keep.slice(0, 5);

const f = $('Job preferences').first().json;
const profile = f['Your resume or profile'] || '';
const rules = 'Rules: Do not use em-dashes, use commas colons or periods instead. Avoid AI-slop words like thrilled, passionate about leveraging, fast-paced world, delve. Use ONLY facts present in the candidate profile text below, never invent skills, employers, dates, metrics or numbers. If the candidate lacks something the job wants, do not claim it, frame it honestly as eager to learn or ramping on. Write in plain, human language.';
const j = $json;
const jd = String(j.jobDescription||'').slice(0,6000);
const role = j.jobTitle||''; const company = (j.companyName||'').replace(/"/g,'');
const PROFILE = 'CANDIDATE PROFILE (the only source of truth, do not invent beyond this): ' + profile;
$json.verifyPrompt = 'You are a STRICT job-eligibility screener. Step 1: infer the candidate total years of experience from their profile (a final-year student or fresher counts as 0 to 1 years). Step 2: find the minimum experience the JD requires, reading the description text for phrases like "3+ years", "5-10 years", "minimum 4 years", "senior", "lead", "principal". Step 3: if the JD clearly requires more experience than the candidate has, OR the title is senior/lead/principal/staff/architect/manager level, set verdict REJECT. Use APPLY only if the candidate genuinely qualifies. Use STRETCH only if the experience gap is small (1 year or less). Return ONLY JSON: {"real_min_years":0,"candidate_years":0,"verdict":"APPLY or STRETCH or REJECT","reason":"one short sentence naming the years required vs the candidate"}. ' + PROFILE + ' ROLE: ' + role + ' at ' + company + '. JD: ' + jd;
$json.resumePrompt = 'Write a tailored resume as JSON for this candidate and job. ' + rules + ' Output ONLY JSON with this shape: {"_company":"' + company + '","basics":{"name":"","title":"","email":"","phone":"","location":"","links":[{"label":"","url":""}]},"summary":"","experience":[],"projects":[{"name":"","url":"","tech":[],"bullets":[]}],"skills":[],"education":[{"degree":"","school":"","dates":""}]}. Extract the name, email, phone and links from the profile text. Keep it to 3 sections (summary, projects, skills); reorder skills so the job-relevant true ones come first; mirror the job wording where it is genuinely true for the candidate. ' + PROFILE + ' ROLE: ' + role + ' at ' + company + '. JD: ' + jd;
$json.coverPrompt = 'Write a humanized cover letter as JSON. ' + rules + ' 5 to 7 short paragraphs, open with the job and company (never "I am writing to apply"), include one honest line if the candidate lacks the required years or pedigree, and include one concrete achievement or number from the profile if one exists. Output ONLY JSON: {"name":"","contact":"","links":[{"label":"","url":""}],"paragraphs":[],"filename":""}. Use the candidate name and contact from the profile. ' + PROFILE + ' ROLE: ' + role + ' at ' + company + '. JD: ' + jd;
return $json;

// ---- RENDER RESUME HTML (port of template.mjs, no em-dash) ----
const esc=s=>String(s==null?'':s).replace(/[&<>]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;'}[c]));
let r={}; try { r = JSON.parse((typeof $json.output==='string'?$json.output:JSON.stringify($json.output||{})).replace(/```json|```/g,'').trim()); } catch(e){ throw new Error('resume JSON parse failed'); }
const b=r.basics||{};
const links=(b.links||[]).map(l=>`<a href="${esc(l.url)}">${esc(l.label)}</a>`).join('<span class="dot">·</span>');
const skills=(r.skills||[]).map(s=>`<span class="skill">${esc(s)}</span>`).join('');
const projects=(r.projects||[]).map(p=>`<div class="entry"><div class="entry-head"><span class="role">${esc(p.name)}</span>${p.url?`<span class=\"dates\"><a href=\"${esc(p.url)}\">${esc(String(p.url).replace(/^https?:\/\//,''))}</a></span>`:''}</div>${p.tech&&p.tech.length?`<div class=\"tech\">${esc(p.tech.join(' · '))}</div>`:''}<ul>${(p.bullets||[]).map(x=>`<li>${esc(x)}</li>`).join('')}</ul></div>`).join('');
const edu=(r.education||[]).map(e=>`<div class="edu-row"><span>${esc(e.degree)}, ${esc(e.school)}</span><span class="dates">${esc(e.dates)}</span></div>`).join('');
const html=`<!doctype html><html><head><meta charset="utf-8"><style>*{box-sizing:border-box}@page{margin:14mm 16mm}body{font-family:Georgia,serif;color:#1a1a1a;font-size:10.5pt;line-height:1.4;margin:0}h1{font-family:Arial,sans-serif;font-size:20pt;letter-spacing:-.02em;margin:0}.title{font-family:Arial,sans-serif;color:#444;font-size:11pt;margin:2px 0 6px}.contact{font-family:Arial,sans-serif;font-size:9pt;color:#333}.contact a{color:#1a4f8b;text-decoration:none}.dot{margin:0 6px;color:#aaa}h2{font-family:Arial,sans-serif;font-size:10.5pt;text-transform:uppercase;letter-spacing:.08em;color:#1a4f8b;border-bottom:1.5px solid #1a4f8b;padding-bottom:2px;margin:16px 0 8px}.summary{margin:8px 0 4px}.skills{display:flex;flex-wrap:wrap;gap:5px}.skill{font-family:Arial,sans-serif;font-size:9pt;background:#eef2f7;border-radius:4px;padding:2px 7px}.entry{margin-bottom:10px}.entry-head{display:flex;align-items:baseline;gap:4px}.role{font-weight:bold}.dates{font-family:Arial,sans-serif;font-size:9pt;color:#666;margin-left:auto}.dates a{color:#666;text-decoration:none}.tech{font-family:Arial,sans-serif;font-size:9pt;color:#555;font-style:italic;margin:1px 0}ul{margin:4px 0 0;padding-left:16px}li{margin-bottom:2px}.edu-row{display:flex;justify-content:space-between}</style></head><body><header><h1>${esc(b.name)}</h1><div class="title">${esc(b.title)}</div><div class="contact">${esc(b.email)}<span class="dot">·</span>${esc(b.phone)}<span class="dot">·</span>${esc(b.location)}${links?`<span class=\"dot\">·</span>${links}`:''}</div></header>${r.summary?`<section><h2>Summary</h2><div class=\"summary\">${esc(r.summary)}</div></section>`:''}${projects?`<section><h2>Projects</h2>${projects}</section>`:''}${skills?`<section><h2>Skills</h2><div class=\"skills\">${skills}</div></section>`:''}${edu?`<section><h2>Education</h2>${edu}</section>`:''}</body></html>`;
return { ...$('Build Prompts (user profile)').item.json, resumeHtml: html, resumeName: (r._company||'resume')+'-resume' };

// ---- RENDER COVER HTML (port of cover-template.mjs, no em-dash) ----
const esc=s=>String(s==null?'':s).replace(/[&<>]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;'}[c]));
let d={}; try { d = JSON.parse((typeof $json.output==='string'?$json.output:JSON.stringify($json.output||{})).replace(/```json|```/g,'').trim()); } catch(e){ throw new Error('cover JSON parse failed'); }
const links=(d.links||[]).map(l=>`<a href="${esc(l.url)}">${esc(l.label)}</a>`).join('<span class="dot"> · </span>');
const paras=(d.paragraphs||[]).map(p=>`<p>${esc(p)}</p>`).join('');
const html=`<!doctype html><html><head><meta charset="utf-8"><style>@page{margin:22mm 20mm}body{font-family:Georgia,serif;color:#1a1a1a;font-size:11pt;line-height:1.65;margin:0}h1{font-family:Arial,sans-serif;font-size:18pt;letter-spacing:-.02em;margin:0}.contact{font-family:Arial,sans-serif;font-size:9.5pt;color:#333;margin:5px 0 0}.contact a{color:#1a4f8b;text-decoration:none}.dot{color:#aaa}hr{border:none;border-top:1.5px solid #1a4f8b;margin:11px 0 18px}p{margin:0 0 12px}</style></head><body><h1>${esc(d.name)}</h1><div class="contact">${esc(d.contact)}${links?`<span class=\"dot\"> · </span>${links}`:''}</div><hr>${paras}</body></html>`;
return { ...$('Render Resume HTML').item.json, coverHtml: html, coverName: (d.filename||'cover-letter') };

// Gather the job info + both PDFs into one item for the email.
const lead = $('Render Cover HTML').item.json;   // jobTitle, companyName, verdict, _fit, applyUrl, reason
const out = { json: lead, binary: {} };
try { out.binary.resumePdf = $('Resume PDF (DocRaptor)').item.binary.resumePdf; } catch (e) {}
try { out.binary.coverPdf  = $('Cover PDF (DocRaptor)').item.binary.coverPdf; } catch (e) {}
return out;
